+function findPreviewableAttachment(
+  attachments: MMFileInfo[] | undefined,
+  serverURL: string,
+  token: string,
+): PreviewFile | null {
+  if (!attachments || attachments.length === 0) return null
+  for (let i = attachments.length - 1; i >= 0; i--) {
+    const file = attachments[i]
+    // Skip media types that have their own renderers (ImageAttachment / AudioAttachment / VideoAttachment)
+    if (file.mime_type.startsWith('image/')) continue
+    if (file.mime_type.startsWith('audio/')) continue
+    if (file.mime_type.startsWith('video/')) continue
+
+    const ext = file.name.includes('.') ? file.name.split('.').pop()?.toLowerCase() : ''
+    if (!ext || !PREVIEWABLE_EXTS.includes(ext)) continue
+
+    return {
+      name: file.name,
+      url: `${serverURL}/api/v4/files/${file.id}`,
+      ext,
+      source: { kind: 'mattermost', token },
+    }
+  }
+  return null
+}

